import React, { useState } from "react";
import { useTranslation } from "react-i18next";
import {
  Table,
  Tag,
  Card,
  Typography,
  Space,
  Button,
  Input,
  theme,
  Modal,
  Descriptions,
  Timeline,
  Divider,
  Flex,
  Badge,
  message
} from "antd";
import {
  SearchOutlined,
  FileTextOutlined,
  FilterOutlined,
  ClockCircleOutlined,
  PrinterOutlined,
  DownloadOutlined,
  CloseOutlined,
  CheckCircleOutlined
} from "@ant-design/icons";
import { QUARANTINE_DB } from "../../../mocks/db";

const { Title, Text } = Typography;

const DetectionLogPage: React.FC = () => {
  const { t } = useTranslation(["quarantine", "history", "common", "monitoring"]);
  const { token } = theme.useToken();
  const [isReportModalOpen, setIsReportModalOpen] = useState(false);
  const [selectedRecord, setSelectedRecord] = useState<any>(null);

  // Use rich history data from DB
  const data = QUARANTINE_DB.history.map((h, i) => ({
    key: i,
    time: h.time,
    target: h.target,
    action: h.action,
    status: h.status,
    detail: h.detail,
    gate: i === 1 ? "G01" : "G12",
    agent: QUARANTINE_DB.agents[i]?.name || "System"
  }));

  const columns = [
    {
      title: t("history:detection.columns.time"),
      dataIndex: "time",
      key: "time",
      render: (text: string) => <Tag icon={<ClockCircleOutlined />} style={{ color: token.colorTextSecondary, background: token.colorFillAlter, border: "none", fontSize: 13, padding: "2px 10px" }}>{text}</Tag>
    },
    { title: t("history:detection.columns.gate"), dataIndex: "gate", key: "gate", render: (t: string) => <Text style={{ fontSize: 13, fontWeight: "bold" }}>{t}</Text> },
    {
      title: t("history:detection.columns.status"),
      dataIndex: "status",
      key: "status",
      render: (s: string) => {
        const color = s === "alert" ? token.colorError : s === "warning" ? token.colorWarning : token.colorInfo;
        return (
          <Tag style={{ background: `${color}26`, borderColor: `${color}40`, color: color, fontWeight: "bold", fontSize: 12, borderRadius: 4, padding: "0 12px" }}>
            {t(`quarantine:common.${s}`).toUpperCase()}
          </Tag>
        );
      }
    },
    { title: t("history:detection.columns.deviceOprtn"), dataIndex: "target", key: "target", render: (t: string) => <Text style={{ fontSize: 13, color: token.colorText }}>{t}</Text> },
    { title: t("history:detection.columns.detail"), dataIndex: "action", key: "action", render: (val: string) => <Text style={{ fontSize: 13, color: token.colorTextSecondary }}>{val}</Text> },
    {
      title: t("history:detection.columns.actionLog"),
      dataIndex: "detail",
      key: "detail",
      render: (val: string) => <Text style={{ color: token.colorTextQuaternary, fontSize: 12 }}>{val}</Text>
    },
    { title: t("history:detection.columns.name"), dataIndex: "agent", key: "agent", render: (val: string) => <Text style={{ fontSize: 13, fontWeight: "bold" }}>{val}</Text> },
    {
      title: t("history:detection.columns.logs"),
      key: "logs",
      align: "center" as const,
      render: (_: any, record: any) => (
        <Button
          type="link"
          size="small"
          icon={<FileTextOutlined />}
          style={{ color: token.colorPrimary, fontWeight: "bold" }}
          onClick={() => {
            setSelectedRecord(record);
            setIsReportModalOpen(true);
          }}
        >
          REPORT
        </Button>
      )
    }
  ];

  return (
    <div className="p-6 h-full flex flex-col" style={{ background: token.colorBgLayout }}>
      <div className="flex justify-between items-center mb-6">
        <Title level={4} style={{ margin: 0, color: token.colorText, fontWeight: "bold" }}>
          {t("history:detection.title")}
        </Title>
        <Space>
          <Input
            placeholder={t("common:search")}
            prefix={<SearchOutlined style={{ color: token.colorTextQuaternary }} />}
            style={{ width: 300, background: token.colorBgContainer, borderRadius: 8, height: 40 }}
          />
          <Button
            style={{ background: token.colorPrimary, color: token.colorTextLightSolid, fontWeight: "bold", height: 40, padding: "0 24px" }}
            icon={<FilterOutlined />}
          >
            {t("quarantine:common.filters")}
          </Button>
        </Space>
      </div>

      <Card
        bordered={false}
        className="shadow-sm flex-1 overflow-hidden"
        style={{ background: token.colorBgContainer, borderRadius: 16 }}
        styles={{ body: { padding: 0 } }}
      >
        <Table
          columns={columns}
          dataSource={data}
          pagination={{ pageSize: 12 }}
          scroll={{ x: 1000, y: 'calc(100vh - 300px)' }}
          className="custom-table"
        />
      </Card>

      <Modal
        title={<Text className="font-bold ml-2" style={{ color: token.colorText, fontSize: 18 }}>{t("quarantine:navigation.dailyReport")}</Text>}
        open={isReportModalOpen}
        onCancel={() => setIsReportModalOpen(false)}
        footer={(
          <Flex justify="end" gap={12} className="p-6 pt-0">
            <Button icon={<PrinterOutlined />} className="btn-vibrant-secondary h-11 px-6" onClick={() => message.info(t("quarantine:common.print"))}>
              {t("quarantine:common.print")}
            </Button>
            <Button icon={<DownloadOutlined />} className="btn-vibrant-secondary h-11 px-6" onClick={() => message.success(t("quarantine:common.download"))}>
              {t("quarantine:common.download")}
            </Button>
            <Button className="btn-vibrant-primary h-11 px-10" onClick={() => setIsReportModalOpen(false)}>
              {t("quarantine:common.confirm")}
            </Button>
          </Flex>
        )}
        centered
        width={750}
        styles={{
          mask: { backdropFilter: "blur(12px)" },
          body: { padding: "32px 24px" },
          header: { padding: "24px 24px 0", marginBottom: 0 }
        }}
        closeIcon={<CloseOutlined style={{ color: token.colorTextQuaternary }} />}
      >
        {selectedRecord && (
          <div className="flex flex-col gap-8">
            <div className="p-6 rounded-2xl border" style={{ background: token.colorFillAlter, borderColor: token.colorBorderSecondary }}>
              <Descriptions column={2} size="small">
                <Descriptions.Item label={t("history:detection.columns.time")}>{selectedRecord.time}</Descriptions.Item>
                <Descriptions.Item label={t("history:detection.columns.gate")}>
                  <Badge status="processing" text={<Text strong style={{ color: token.colorText }}>{selectedRecord.gate}</Text>} />
                </Descriptions.Item>
                <Descriptions.Item label={t("history:detection.columns.name")}>{selectedRecord.agent}</Descriptions.Item>
                <Descriptions.Item label={t("history:detection.columns.status")}>
                  <Tag color={selectedRecord.status === "success" ? "blue" : "warning"} variant="filled">
                    {t(`quarantine:common.${selectedRecord.status}`).toUpperCase()}
                  </Tag>
                </Descriptions.Item>
              </Descriptions>
            </div>

            <div>
              <Title level={5} className="mb-6 flex items-center gap-2" style={{ color: token.colorText }}>
                <div style={{ width: 4, height: 16, background: token.colorPrimary, borderRadius: 2 }} />
                {t("monitoring:deviceOpHistory")}
              </Title>
              <div className="px-4">
                <Timeline
                  items={[
                    {
                      color: token.colorPrimary,
                      children: (
                        <div>
                          <Text strong className="block mb-1" style={{ color: token.colorText }}>{selectedRecord.action}</Text>
                          <Text type="secondary" style={{ fontSize: 13 }}>{selectedRecord.detail}</Text>
                        </div>
                      ),
                    },
                    {
                      color: 'gray',
                      children: <Text style={{ color: token.colorTextDescription }}>장비 초기화 및 연결 확인</Text>,
                    },
                    {
                      dot: <CheckCircleOutlined style={{ fontSize: 16, color: token.colorSuccess }} />,
                      color: token.colorSuccess,
                      children: <Text style={{ color: token.colorTextDescription }}>검역 절차 정상 종료 및 데이터 서버 전송 완료</Text>,
                    },
                  ]}
                />
              </div>
            </div>
            <Divider className="my-0" />
          </div>
        )}
      </Modal>

      <style>{`
        .custom-table .ant-table { background: transparent !important; }
        .custom-table .ant-table-thead > tr > th { 
          background: ${token.colorFillAlter} !important; 
          color: ${token.colorTextDescription} !important; 
          font-size: 13px !important; 
          font-weight: bold !important;
          border-bottom: 2px solid ${token.colorBorderSecondary} !important;
          text-align: center !important;
        }
        .custom-table .ant-table-tbody > tr > td { 
           border-bottom: 1px solid ${token.colorBorderSecondary} !important; 
           padding: 16px !important;
           text-align: center !important;
        }
        
        /* Solid Button System (High Contrast & Unified Blue - Per User Screenshot) */
        .btn-vibrant-primary, .btn-vibrant-secondary, .btn-vibrant-danger, .btn-vibrant-info, .btn-vibrant-warning { 
          background: ${token.colorPrimary} !important; 
          border-color: ${token.colorPrimary} !important; 
          color: #fff !important; 
          font-weight: bold !important; 
          border-radius: 6px !important; 
          transition: all 0.2s cubic-bezier(0.175, 0.885, 0.32, 1.275);
        }

        .btn-vibrant-primary:hover {
          filter: brightness(1.1) saturate(1.1);
          box-shadow: 0 4px 12px ${token.colorPrimary}40;
          transform: translateY(-1px);
        }
        .btn-vibrant-secondary {
          background: ${token.colorFillAlter} !important;
          border: 1px solid ${token.colorBorderSecondary} !important;
          color: ${token.colorTextDescription} !important;
          font-weight: bold !important;
          border-radius: 6px !important;
          transition: all 0.2s ease;
          display: flex;
          align-items: center;
          justify-content: center;
        }
        .btn-vibrant-secondary:hover {
          background: ${token.colorFillSecondary} !important;
          color: ${token.colorText} !important;
          border-color: ${token.colorBorder} !important;
        }

        @keyframes fade-in { from { opacity: 0; } to { opacity: 1; } }
        .animate-in { animation: fade-in 0.3s ease-out; }
      `}</style>
    </div>
  );
};

export default DetectionLogPage;
